#!/bin/bash\n# report-state.sh\n# Called by stage-complete hook on agentStop.\n# Writes session state to .kiro/state/session-state.json and commits to git.\n# Cowork monitors this file via GitHub to advance the SDLC stage in Linear.\n\nSTATE_DIR=".kiro/state"\nSTATE_FILE="$STATE_DIR/session-state.json"\nSPECS_DIR=".kiro/specs"\n\nmkdir -p "$STATE_DIR"\n\nTOTAL=$(grep -r "^\\- \\[" "$SPECS_DIR" 2>/dev/null | wc -l | tr -d ' ')\nDONE=$(grep -r "^\\- \\[x\\]" "$SPECS_DIR" 2>/dev/null | wc -l | tr -d ' ')\nPENDING=$(grep -r "^\\- \\[ \\]" "$SPECS_DIR" 2>/dev/null | wc -l | tr -d ' ')\n\nif [ "$PENDING" -eq 0 ] && [ "$TOTAL" -gt 0 ]; then\n  STATUS="complete"\nelif [ "$DONE" -gt 0 ]; then\n  STATUS="in_progress"\nelse\n  STATUS="started"\nfi\n\ncat > "$STATE_FILE" << EOF\n{\n  "status": "$STATUS",\n  "timestamp": "$(date -u +%Y-%m-%dT%H:%M:%SZ)",\n  "tasks_total": $TOTAL,\n  "tasks_done": $DONE,\n  "tasks_pending": $PENDING,\n  "machine": "$(hostname)",\n  "branch": "$(git rev-parse --abbrev-ref HEAD 2>/dev/null || echo 'unknown')"\n}\nEOF\n\ngit add "$STATE_FILE" 2>/dev/null\ngit commit -m "chore: session state [$STATUS] $DONE/$TOTAL tasks" --no-verify 2>/dev/null\n\necho "State: $STATUS ($DONE/$TOTAL tasks complete)"\nexit 0\n